     1→import { anthropic } from "@ai-sdk/anthropic";
     2→import {
     3→  convertToModelMessages,
     4→  createUIMessageStream,
     5→  createUIMessageStreamResponse,
     6→  streamText,
     7→  TypeValidationError,
     8→  type UIMessage,
     9→  validateUIMessages,
    10→} from "ai";
    11→import type { NextRequest } from "next/server";
    12→import { after } from "next/server";
    13→import { trace } from "@opentelemetry/api";
    14→import { authenticateUser } from "@/app/api/(universal)/venus-9/v2/image/venus-9-utils/authenticateUser";
    15→import {
    16→  observe,
    17→  updateActiveObservation,
    18→  updateActiveTrace,
    19→} from "@langfuse/tracing";
    20→import { langfuseSpanProcessor } from "../../../../../instrumentation";
    21→import { main_agent_prompt, manual_mode_agent_prompt } from "@/lib/langfuse/prompt";
    22→import { getPromptWithFallback } from "@/lib/langfuse/prompt-fetcher";
    23→import {
    24→  bgRemoverTool,
    25→  GenerateEditImageTools,
    26→  generateAudioTool,
    27→  generateImageWithPollingTool,
    28→  generateVideoWithPollingTool,
    29→  imageResizerTool,
    30→  imageUpscalerTool,
    31→} from "@/lib/agents/model-suggester/tools";
    32→import {
    33→  createChat,
    34→  getChatById,
    35→} from "@/server/database/repo/postgress-repo-functions/chat.repo";
    36→import {
    37→  loadChatMessages,
    38→  saveChatMessage,
    39→} from "@/server/database/repo/postgress-repo-functions/chatMessage.repo";
    40→import { findProjectByIdForUser } from "@/server/database/repo/postgress-repo-functions/imageEditorProjects.repo";
    41→import logger from "@/utils/logger";
    42→
    43→// Define tools object for validation and streaming
    44→const tools = {
    45→  generateImageWithPolling: generateImageWithPollingTool,
    46→  generateVideoWithPolling: generateVideoWithPollingTool,
    47→  GenerateEditImage: GenerateEditImageTools,
    48→  generateAudio: generateAudioTool,
    49→  bgRemover: bgRemoverTool,
    50→  imageResizer: imageResizerTool,
    51→  imageUpscaler: imageUpscalerTool,
    52→};
    53→
    54→// Allow streaming up to 180s
    55→export const maxDuration = 180;
    56→
    57→const handler = async (req: NextRequest) => {
    58→  const requestId = crypto.randomUUID();
    59→  const { id: userId } = await authenticateUser(requestId);
    60→
    61→  // Get the last message, projectId, and optionally chatId from client
    62→  const {
    63→    message,
    64→    id: projectId,
    65→    chatId: clientChatId,
    66→    globalSystemInstructions,
    67→    modelSelection,
    68→  }: {
    69→    message: UIMessage;
    70→    id: string;
    71→    chatId?: string;
    72→    globalSystemInstructions?: string;
    73→    modelSelection?: {
    74→      isAutoMode: boolean;
    75→      imageModel: string | null;
    76→      videoModel: string | null;
    77→    };
    78→  } = await req.json();
    79→
    80→  // Log model selection for debugging
    81→  logger.info(`Model selection received: ${JSON.stringify(modelSelection)}`);
    82→
    83→  const initialTraceInput =
    84→    extractTextFromUiMessage(message) ??
    85→    `[${message.role}] ${summarizeParts(message.parts)}`;
    86→
    87→  try {
    88→    // Verify project exists and user owns it
    89→    const project = await findProjectByIdForUser({ projectId, userId });
    90→    if (!project) {
    91→      logger.error("Project not found or access denied");
    92→      return new Response(
    93→        JSON.stringify({ error: "Project not found or access denied" }),
    94→        { status: 403, headers: { "Content-Type": "application/json" } },
    95→      );
    96→    }
    97→
    98→    // Resolve or create chat
    99→    // Client always sends a chatId (either existing or pre-generated UUID)
   100→    let chat: Awaited<ReturnType<typeof getChatById>> | null = null;
   101→    let previousMessages: UIMessage[] = [];
   102→
   103→    if (!clientChatId) {
   104→      // Chat not found with provided chatId - create a new chat
   105→      logger.error("No chatId provided by client", {
   106→        requestId,
   107→        userId,
   108→        projectId,
   109→      });
   110→      return new Response(
   111→        JSON.stringify({
   112→          error:
   113→            "chatId is required but was not provided. This usually indicates an outdated or misconfigured client. Please refresh the page or update the client and try again.",
   114→        }),
   115→        {
   116→          status: 400,
   117→          headers: { "Content-Type": "application/json" },
   118→        },
   119→      );
   120→    }
   121→
   122→    // Update Langfuse trace with context (now that we have a chat/session id)
   123→    updateActiveTrace({
   124→      name: "agent-chat-message",
   125→      sessionId: clientChatId,
   126→      userId,
   127→      input: initialTraceInput,
   128→      metadata: {
   129→        projectId,
   130→        requestId,
   131→        isManualMode: modelSelection ? !modelSelection.isAutoMode : false,
   132→      },
   133→    });
   134→
   135→    updateActiveObservation({
   136→      input: initialTraceInput,
   137→    });
   138→
   139→    // Try to get existing chat
   140→    chat = await getChatById({ chatId: clientChatId, userId });
   141→
   142→    if (chat) {
   143→      // Existing chat - load messages
   144→      previousMessages = await loadChatMessages(chat.id, userId);
   145→    } else {
   146→      // No chatId provided - create a new chat
   147→
   148→      chat = await createChat({
   149→        id: clientChatId, // Use client's pre-generated ID
   150→        projectId,
   151→        userId,
   152→        title: "New Chat",
   153→      });
   154→
   155→      if (!chat) {
   156→        logger.error("Failed to create chat");
   157→        return new Response(
   158→          JSON.stringify({ error: "Failed to create chat" }),
   159→          { status: 500, headers: { "Content-Type": "application/json" } },
   160→        );
   161→      }
   162→      // No previous messages for new chat
   163→      previousMessages = [];
   164→    }
   165→
   166→    // Track continuation message ID to maintain consistent IDs across multi-step tool execution
   167→    // When client sends an assistant message (via sendAutomaticallyWhen), we reuse its ID
   168→    // so all steps share the same message ID (like DB upsert pattern)
   169→    let continuationMessageId: string | undefined;
   170→
   171→    // Build messages array for LLM based on incoming message role
   172→    let messages: UIMessage[];
   173→
   174→    if (message.role === "user") {
   175→      // User message: append to conversation history
   176→      messages = [...previousMessages, message];
   177→      logger.info(`User message received, total messages: ${messages.length}`);
   178→    } else if (message.role === "assistant") {
   179→      // Assistant message sent by client's sendAutomaticallyWhen
   180→      // Preserve the client's message ID for consistency
   181→      continuationMessageId = message.id;
   182→      // Use only previous messages (new assistant message will be generated)
   183→      messages = previousMessages;
   184→      logger.info(
   185→        `Assistant message received (auto-continuation), using ${messages.length} previous messages, continuationId: ${continuationMessageId}`,
   186→      );
   187→    } else {
   188→      // Unexpected role (system, etc.)
   189→      logger.warn(`Unexpected message role: ${message.role}`);
   190→      messages = [...previousMessages, message];
   191→    }
   192→
   193→    const bestTraceInput =
   194→      extractLatestUserTextFromUiMessages(messages) ?? initialTraceInput;
   195→
   196→    updateActiveObservation({ input: bestTraceInput });
   197→    updateActiveTrace({ input: bestTraceInput });
   198→
   199→    // Validate messages against tool schemas to ensure compatibility
   200→    let validatedMessages: UIMessage[];
   201→    try {
   202→      validatedMessages = await validateUIMessages({
   203→        messages,
   204→        // biome-ignore lint/suspicious/noExplicitAny: Because we have specific tightly typed tools types
   205→        tools: tools as any,
   206→      });
   207→    } catch (error) {
   208→      if (error instanceof TypeValidationError) {
   209→        // Log validation error for monitoring
   210→        logger.warn(
   211→          `Message validation failed, starting with only new message: ${error.message}`,
   212→        );
   213→        // If validation fails (e.g., old tool schemas), start fresh with just the new message
   214→        validatedMessages = [message];
   215→      } else {
   216→        throw error;
   217→      }
   218→    }
   219→
   220→    // Save user message to database immediately (before streaming)
   221→    // Assistant messages are saved in onFinish callback after streaming completes
   222→    if (message.role === "user") {
   223→      await saveChatMessage({ message, chatId: chat.id, userId });
   224→      logger.info(`User message saved: ${message.id}`);
   225→    }
   226→
   227→    // Client now sends images in correct AI SDK format (type: "file")
   228→    // No server-side normalization needed
   229→
   230→    // Choose the appropriate system prompt based on Auto mode
   231→    // When Auto is ON: use main_agent_prompt (includes model selection logic)
   232→    // When Auto is OFF: use manual_mode_agent_prompt (uses user's selected models directly)
   233→    const isManualMode = modelSelection && !modelSelection.isAutoMode;
   234→
   235→    let baseSystemPrompt: string;
   236→    if (isManualMode) {
   237→      // Manual mode: fetch prompt from Langfuse with fallback
   238→      const manualPromptFallback = manual_mode_agent_prompt(
   239→        modelSelection.imageModel,
   240→        modelSelection.videoModel
   241→      );
   242→      baseSystemPrompt = await getPromptWithFallback(
   243→        "manual_mode_agent_prompt",
   244→        manualPromptFallback
   245→      );
   246→      logger.info(`Manual mode enabled - Image: ${modelSelection.imageModel}, Video: ${modelSelection.videoModel}`);
   247→    } else {
   248→      // Auto mode: fetch main agent prompt from Langfuse with fallback
   249→      baseSystemPrompt = await getPromptWithFallback(
   250→        "main_agent_prompt",
   251→        main_agent_prompt
   252→      );
   253→      logger.info("Auto mode enabled - agent will select best models");
   254→    }
   255→
   256→    // Merge with user's custom system instructions if provided
   257→    const mergedSystem = [
   258→      baseSystemPrompt,
   259→      globalSystemInstructions?.trim().length
   260→        ? `\n\n<user-system-instructions>\n${globalSystemInstructions.trim()}\n</user-system-instructions>\n`
   261→        : "",
   262→    ].join("");
   263→
   264→    // Convert to model messages (this is what gets sent to OpenAI)
   265→    const modelMessages = await convertToModelMessages(validatedMessages, {
   266→      ignoreIncompleteToolCalls: true,
   267→    });
   268→
   269→    const result = await streamText({
   270→      model: anthropic("claude-haiku-4-5"),
   271→      // providerOptions: {
   272→      //   anthropic: {
   273→      //     // effort: "low", // or "medium" - saves tokens + faster TTLT
   274→      //     disableParallelToolUse: true,
   275→      //   } satisfies AnthropicProviderOptions,
   276→      // },
   277→      headers: {
   278→        "anthropic-beta": "fine-grained-tool-streaming-2025-05-14",
   279→      },
   280→      system: mergedSystem,
   281→      maxOutputTokens: 10_000,
   282→      maxRetries: 3,
   283→      // Convert validated messages to model messages (this is what gets sent to the model)
   284→      messages: modelMessages,
   285→      tools,
   286→      experimental_telemetry: { isEnabled: true },
   287→      onAbort: ({ steps }) => {
   288→        const completedSteps = steps.filter(
   289→          (s) => s.finishReason === "stop",
   290→        ).length;
   291→        logger.info(
   292→          `Stream aborted by user: requestId=${requestId}, totalSteps=${steps.length}, completedSteps=${completedSteps}`,
   293→        );
   294→      },
   295→    });
   296→
   297→    // Handling client disconnects:
   298→    // By default, streamText uses backpressure (pauses when client isn't reading).
   299→    // If client disconnects (tab closed, network issue), the stream aborts and onFinish may not run.
   300→    // consumeStream() removes backpressure, allowing the stream to complete server-side
   301→    // even after client disconnect, ensuring onFinish runs and messages are saved.
   302→    result.consumeStream(); // no await - fire and forget
   303→
   304→    // Flush Langfuse traces after the response is sent (serverless-friendly)
   305→    after(async () => {
   306→      await langfuseSpanProcessor.forceFlush();
   307→    });
   308→
   309→    // Return proper UI message stream response with enhanced error handling
   310→    return result.toUIMessageStreamResponse({
   311→      originalMessages: validatedMessages,
   312→      // Use continuation message ID for multi-step tool execution (upsert pattern)
   313→      // This ensures client receives consistent IDs across all steps
   314→      generateMessageId: () => continuationMessageId || crypto.randomUUID(),
   315→      onError: (error) => {
   316→        // Enhanced error logging with type checking
   317→        if (error instanceof Error) {
   318→          logger.error(
   319→            `Stream error occurred: name=${error.name}, message=${error.message}, requestId=${requestId}, stack=${error.stack}`,
   320→          );
   321→        } else {
   322→          logger.error(
   323→            `Unknown stream error: error=${JSON.stringify(error)}, requestId=${requestId}`,
   324→          );
   325→        }
   326→
   327→        // Return context-aware error messages
   328→        const errorMessage = error instanceof Error ? error.message : "";
   329→
   330→        if (errorMessage.includes("rate limit")) {
   331→          return "I'm experiencing high demand right now. Please try again in a moment.";
   332→        }
   333→
   334→        if (errorMessage.includes("timeout")) {
   335→          return "The request took too long. Please try a simpler question.";
   336→        }
   337→
   338→        if (errorMessage.includes("context length")) {
   339→          return "The conversation is too long. Please start a new chat.";
   340→        }
   341→
   342→        const messageToUser =
   343→          "Sorry, I am not able to respond right now. Please try again later.";
   344→
   345→        updateActiveObservation({
   346→          output: messageToUser,
   347→          level: "ERROR",
   348→        });
   349→        updateActiveTrace({
   350→          output: messageToUser,
   351→        });
   352→
   353→        trace.getActiveSpan()?.end();
   354→        return messageToUser;
   355→      },
   356→      onFinish: async ({ responseMessage }) => {
   357→        // Update Langfuse trace with output
   358→        const outputText = responseMessage
   359→          ? extractTextFromUiMessage(responseMessage)
   360→          : undefined;
   361→
   362→        const outputForTrace =
   363→          outputText ??
   364→          (responseMessage
   365→            ? `[assistant] ${summarizeParts(responseMessage.parts)}`
   366→            : undefined);
   367→
   368→        updateActiveObservation({
   369→          output: outputForTrace,
   370→        });
   371→
   372→        updateActiveTrace({
   373→          output: outputForTrace,
   374→        });
   375→
   376→        trace.getActiveSpan()?.end();
   377→
   378→        // Save assistant response message to database
   379→        // Upsert will update if already exists (from previous tool-only saves)
   380→        if (responseMessage) {
   381→          // ID priority: responseMessage.id > continuationMessageId > new UUID
   382→          // This ensures multi-step tool executions share the same message ID
   383→          const messageId =
   384→            responseMessage.id || continuationMessageId || crypto.randomUUID();
   385→
   386→          const messageToSave: UIMessage = {
   387→            ...responseMessage,
   388→            id: messageId,
   389→          };
   390→
   391→          try {
   392→            await saveChatMessage({
   393→              message: messageToSave,
   394→              chatId: chat.id,
   395→              userId,
   396→            });
   397→            logger.info(
   398→              `Assistant message saved: ${messageToSave.id} (${messageToSave.parts.length} parts)`,
   399→            );
   400→          } catch (saveError) {
   401→            logger.error(
   402→              `Failed to save assistant message: ${saveError instanceof Error ? saveError.message : String(saveError)}`,
   403→            );
   404→          }
   405→        }
   406→      },
   407→    });
   408→  } catch (error) {
   409→    // Enhanced pre-stream error logging
   410→    const errorMessage =
   411→      error instanceof Error ? error.message : "Unknown error";
   412→    const stack = error instanceof Error ? error.stack : "no stack";
   413→    logger.error(
   414→      `Error in POST request (before streaming): error=${errorMessage}, requestId=${requestId}, stack=${stack}`,
   415→    );
   416→
   417→    // Update Langfuse trace with error
   418→    updateActiveObservation({
   419→      output: errorMessage,
   420→      level: "ERROR",
   421→    });
   422→
   423→    updateActiveTrace({
   424→      output: errorMessage,
   425→    });
   426→
   427→    trace.getActiveSpan()?.end();
   428→
   429→    try {
   430→      const textId = crypto.randomUUID();
   431→
   432→      const stream = createUIMessageStream<UIMessage>({
   433→        originalMessages: [message],
   434→        execute: ({ writer }) => {
   435→          writer.write({ type: "text-start", id: textId });
   436→          writer.write({
   437→            type: "text-delta",
   438→            id: textId,
   439→            delta:
   440→              "Sorry, I am not able to respond right now. Please try again later.",
   441→          });
   442→          writer.write({ type: "text-end", id: textId });
   443→        },
   444→      });
   445→
   446→      return createUIMessageStreamResponse({ stream });
   447→    } catch (streamError) {
   448→      const streamErrorMsg =
   449→        streamError instanceof Error
   450→          ? streamError.message
   451→          : String(streamError);
   452→      logger.error(
   453→        `Failed to create error stream: error=${streamErrorMsg}, requestId=${requestId}`,
   454→      );
   455→
   456→      // Fallback to plain text response if stream creation fails
   457→      return new Response(
   458→        JSON.stringify({
   459→          error:
   460→            "An error occurred while processing your request. Please try again.",
   461→        }),
   462→        {
   463→          status: 500,
   464→          headers: { "Content-Type": "application/json" },
   465→        },
   466→      );
   467→    }
   468→  }
   469→};
   470→
   471→// Wrap handler with Langfuse observe for automatic tracing
   472→// endOnExit: false keeps the observation open during streaming
   473→export const POST = observe(handler, {
   474→  name: "handle-agent-chat",
   475→  endOnExit: false,
   476→});
   477→
   478→function extractTextFromUiMessage(message: UIMessage): string | undefined {
   479→  return extractTextFromParts(message.parts);
   480→}
   481→
   482→function extractTextFromParts(parts: UIMessage["parts"]): string | undefined {
   483→  const chunks: string[] = [];
   484→  for (const part of parts) {
   485→    if (part.type === "text") {
   486→      chunks.push(part.text);
   487→    }
   488→  }
   489→  const text = chunks.join("");
   490→  return text.trim().length ? text : undefined;
   491→}
   492→
   493→function extractLatestUserTextFromUiMessages(messages: UIMessage[]): string | undefined {
   494→  for (let i = messages.length - 1; i >= 0; i -= 1) {
   495→    const msg = messages[i];
   496→    if (msg.role !== "user") continue;
   497→    const text = extractTextFromUiMessage(msg);
   498→    if (text) return text;
   499→  }
   500→  return undefined;
   501→}
   502→
   503→function summarizeParts(parts: UIMessage["parts"]): string {
   504→  const counts = new Map<string, number>();
   505→  for (const part of parts) {
   506→    counts.set(part.type, (counts.get(part.type) ?? 0) + 1);
   507→  }
   508→  const summary = [...counts.entries()]
   509→    .map(([type, count]) => `${type}:${count}`)
   510→    .join(", ");
   511→
   512→  return summary.length ? `parts(${summary})` : "parts(empty)";
   513→}
