    24→export const onRequestError = async (
    25→  err: Error,
    26→  request: any,
    27→  context: any,
    28→) => {
    29→  if (process.env.NEXT_RUNTIME === "nodejs") {
    30→    const posthog = await getPostHogServer();
    31→    if (!posthog) {
    32→      return;
    33→    }
    34→    let distinctId = null;
    35→    if (request.headers.cookie) {
    36→      const cookieString = request.headers.cookie;
    37→      const postHogCookieMatch = cookieString?.match(
    38→        /ph_phc_.*?_posthog=([^;]+)/,
    39→      );
    40→
    41→      if (postHogCookieMatch && postHogCookieMatch[1]) {
    42→        try {
    43→          const decodedCookie = decodeURIComponent(postHogCookieMatch[1]);
    44→          const postHogData = JSON.parse(decodedCookie);
    45→          distinctId = postHogData.distinct_id;
    46→        } catch (e) {
    47→          console.error("Error parsing PostHog cookie:", e);
    48→        }
    49→      }
    50→    }
    51→
    52→    await posthog.captureException(err, distinctId || undefined);
    53→  }
    54→};
